&lt;p&gt;&amp;nbsp;&lt;/p&gt;
&lt;p style=&quot;text-align: left; line-height: 1.1;&quot;&gt;&amp;nbsp;&lt;/p&gt;
&lt;ul style=&quot;text-align: left;&quot;&gt;
&lt;li&gt;Interact with customer service to resolve customer and order issues&lt;/li&gt;
&lt;/ul&gt;
&lt;p style=&quot;text-align: left; line-height: 1.1;&quot;&gt;&amp;nbsp;&lt;/p&gt;
&lt;ul&gt;
